const express = require('express');
const session = require('express-session');
const bodyParser = require('body-parser');
const twilio = require('twilio');

const app = express();
const client = twilio('YOUR_TWILIO_ACCOUNT_SID', 'YOUR_TWILIO_AUTH_TOKEN');

app.use(session({
  secret: 'secret_key',
  resave: false,
  saveUninitialized: true
}));
app.use(bodyParser.urlencoded({ extended: true }));

function generateRandomCode() {
  return Math.floor(100000 + Math.random() * 900000);
}

app.get('/send-code', (req, res) => {
  const code = generateRandomCode();
  req.session.code = code;

  client.messages.create({
    body: `Your verification code is: ${code}`,
    from: 'YOUR_TWILIO_PHONE_NUMBER',
    to: 'USER_PHONE_NUMBER'
  })
  .then(() => {
    res.send('Verification code sent successfully.');
  })
  .catch(() => {
    res.status(500).send('Failed to send verification code.');
  });
});

app.post('/verify-code', (req, res) => {
  const userCode = parseInt(req.body.code);
  const storedCode = req.session.code;

  if (userCode === storedCode) {
    res.send('Verification successful');
  } else {
    res.status(400).send('Verification failed. Incorrect code.');
  }
});

app.listen(3000, () => {
  console.log('Server is running on port 3000');
});